+    /// bd-xb07w: morsel-driven INSERT dispatch. Splits materialized rows into
+    /// fixed-size morsels via [`MorselScheduler`] and executes each batch
+    /// through the row-stream replay mechanism. Currently sequential; the
+    /// morsel split validates the wiring and prepares for future parallel
+    /// worker dispatch via `asupersync`.
+    fn execute_morsel_insert(
+        &self,
+        insert: &fsqlite_ast::InsertStatement,
+        source_rows: Vec<Row>,
+    ) -> Result<usize> {
+        let total_rows = source_rows.len();
+        let scheduler = MorselScheduler::new(1, MORSEL_INSERT_SIZE);
+        let value_rows: Vec<Vec<SqliteValue>> = source_rows.into_iter().map(|r| r.values).collect();
+        let morsels = scheduler.split_into_morsels(0, 0, value_rows);
+        let mut total_changes = 0usize;
+        for morsel in &morsels {
+            let morsel_rows: Vec<Row> = morsel
+                .rows
+                .iter()
+                .map(|values| Row {
+                    values: values.clone(),
+                })
+                .collect();
+            total_changes += self.execute_insert_select_materialized_rows(insert, &morsel_rows)?;
+        }
+        debug_assert_eq!(
+            total_changes, total_rows,
+            "morsel INSERT should affect exactly as many rows as input"
+        );
+        Ok(total_changes)
+    }
